 frameRate: { num: 30, den: 1 }
});

// Raw audio input
const rawAudio = await Demuxer.open({
 type: 'audio',
 input: 'input.pcm',
 sampleRate: 48000,
 channels: 2,
 sampleFormat: AV_SAMPLE_FMT_S16
}, {
 format: 's16le'
});Device Capture ​Capture video, audio, and screen content directly from system devices. Platform-specific formats are handled automatically.typescriptimport { DeviceAPI } from 'node-av/api';

// List devices and query capabilities
const devices = await DeviceAPI.list();
const modes = await DeviceAPI.modes(devices.find(d => d.type === 'video')!.name);

// Camera
await using camera = await DeviceAPI.openCamera({ videoDevice: 0, width: 1280, height: 720, frameRate: 30 });

// Microphone
await using mic = await DeviceAPI.openMicrophone({ audioDevice: 0, sampleRate: 48000, channels: 2 });

// Combined video + audio (macOS/Windows)
await using device = await DeviceAPI.openDevice({ videoDevice: 0, audioDevice: 0, width: 1280, height: 720, frameRate: 30 });

// Screen capture
await using screen = await DeviceAPI.openScreen({ frameRate: 30, drawMouse: true });

// Screen capture with system audio (macOS 13.0+)
await using screen2 = await DeviceAPI.openScreen({
 frameRate: 30,
 avfoundation: { captureSystemAudio: true, audioSampleRate: 48000, audioChannels: 2 },
});PlatformVideoAudioScreenmacOSAVFoundationAVFoundationAVFoundation (ScreenCaptureKit)LinuxV4L2ALSAx11grabWindowsDirectShowDirectShowGDIGrabFFmpeg Binary Access ​Need direct access to the FFmpeg binary? The library provides an easy way to get FFmpeg binaries that automatically downloads and manages platform-specific builds.typescriptimport { ffmpegPath, isFfmpegAvailable } from 'node-av/ffmpeg';
import { execFile } from 'node:child_process';
import { promisify } from 'node:util';

const execFileAsync = promisify(execFile);

// Check if FFmpeg binary is available
if (isFfmpegAvailable()) {
 console.log('FFmpeg binary found at:', ffmpegPath());

 // Use FFmpeg binary directly
 const { stdout } = await execFileAsync(ffmpegPath(), ['-version']);
 console.log(stdout);
} else {
 console.log('FFmpeg binary not available - install may have failed');
}

// Direct usage example
async function convertVideo(input: string, output: string) {
 const args = [
 '-i', input,
 '-c:v', 'libx264',
 '-crf', '23',
 '-c:a', 'aac',
 output
 ];

 await execFileAsync(ffmpegPath(), args);
}The FFmpeg binary is automatically downloaded during installation from GitHub releases and matches the same build used by the native bindings.Resource Management ​The library supports automatic resource cleanup using the Disposable pattern:typescript// Automatic cleanup with 'using'
{
 await using media = await Demuxer.open('input.mp4');
 using decoder = await Decoder.create(media.video());
 // Resources automatically cleaned up at end of scope
}

// Manual cleanup
const media = await Demuxer.open('input.mp4');
try {
 // Process media
} finally {
 await media.close();
}Imports and Tree Shaking ​The library provides multiple entry points for optimal tree shaking:typescript// High-Level API only - Recommended for most use cases
import { Demuxer, Muxer, Decoder, Encoder } from 'node-av/api';

// Low-Level API only - Direct FFmpeg bindings
import { FormatContext, CodecContext, Frame, Packet } from 'node-av/lib';

// Constants only - When you just need FFmpeg constants
import { AV_PIX_FMT_YUV420P, AV_CODEC_ID_H264 } from 'node-av/constants';

// Channel layouts only - For audio channel configurations
import { AV_CHANNEL_LAYOUT_STEREO, AV_CHANNEL_LAYOUT_5POINT1 } from 'node-av/layouts';

// Default export - Includes everything
import * as ffmpeg from 'node-av';Key Features ​Beyond basic transcoding, NodeAV provides advanced media processing capabilities:Fully Typed FFmpeg Options Every FFmpeg option is typed - across codecs, formats, ~580 filters, and bitstream filters. Keys autocomplete, enum values are validated, and typos become compile-time errors, all generated directly from FFmpeg's AVOption metadata (including each option's description and a link to the FFmpeg docs as JSDoc). No more grepping the FFmpeg docs for flag names.Speech Recognition with Whisper Integrate automatic speech-to-text transcription using OpenAI's Whisper model through the whisper.cpp implementation. The library handles automatic model downloading from HuggingFace, supports multiple model sizes (tiny, base, small, medium, large) for different accuracy/performance tradeoffs, and provides hardware-accelerated inference through Metal (macOS), Vulkan (cross-platform), or OpenCL backends. Transcription results include precise timestamps and can be processed in real-time from any audio source.Advanced Video Filtering with FilterComplexAPI Build sophisticated video processing pipelines using FFmpeg's complete filter ecosystem. The FilterComplexAPI provides direct access to complex filtergraphs with multiple inputs and outputs, enabling advanced operations like picture-in-picture overlays, multi-stream composition (side-by-side, grid layouts), real-time video effects, and custom processing chains. All filters support hardware acceleration where available, and filter configurations can be dynamically constructed based on runtime requirements.Browser Streaming Stream any media source directly to web browsers through fragmented MP4 (fMP4) or WebRTC protocols. The library can process inputs from RTSP cameras, local files, network streams, or custom sources and package them for browser consumption with minimal latency. Complete examples demonstrate both Media Source Extensions (MSE) based playback for on-demand content and WebRTC integration for real-time streaming scenarios.RTSP Backchannel / Talkback Implements bidirectional RTSP communication for IP camera integration. The library provides native support for RTSP backchannel streams, enabling audio transmission to camera devices. Transport is handled automatically with support for both TCP (interleaved mode) and UDP protocols, with proper RTP packet formatting and stream synchronization.Image Scaling & Snapshots The Scaler turns decoded frames into raw pixel buffers (rgb/rgba/gray/nv12/yuv420p) or JPEG/PNG images for detection, thumbnail, and snapshot workloads. One reusable instance pools its swscale contexts, GPU filter graphs, and encoders for zero per-frame allocation; hardware frames are cropped/scaled on the GPU with only the small result downloaded. Recurring resolutions can also be served directly by EncoderPool.See the Examples section for complete implementations.Performance ​NodeAV executes all media operations directly through FFmpeg's native C libraries. The Node.js bindings add minimal overhead - mostly just the JavaScript-to-C boundary crossings. During typical operations like transcoding or filtering, most processing time is spent in FFmpeg's optimized C code.Benchmarks ​Performance comparison with FFmpeg CLI (4K 60fps, 30s test files on Apple M3 Max):OperationFFmpeg CLI (FPS)node-av (FPS)FFmpeg CLI (Time)node-av (Time)DiffSW H.264 Transcode96 fps96 fps18.7s18.7s≈0%SW H.265 Transcode40 fps41 fps44.5s43.7s+1.5%HW H.264 Transcode55 fps55 fps33.0s32.8s+0.5%Stream Copy (Remux)48k fps31k fps38ms106ms-35%Memory Usage:OperationFFmpeg CLInode-avDifferenceH.264 Transcode (4K)3.6 GB3.4 GB-5%Stream Copy28 MB1 MB-96%📊 Full benchmark resultsSync vs Async Operations ​Every async method in NodeAV has a corresponding synchronous variant with the Sync suffix:Async methods (default) - Non-blocking operations using N-API's AsyncWorker. Methods like decode(), encode(), read(), packets() return Promises or AsyncGenerators.Sync methods - Direct FFmpeg calls without AsyncWorker overhead. Same methods with Sync suffix: decodeSync(), encodeSync(), readSync(), packetsSync().The key difference: Async methods don't block the Node.js event loop, allowing other operations to run concurrently. Sync methods block until completion but avoid AsyncWorker overhead, making them faster for sequential processing.Memory Safety Considerations ​NodeAV provides direct bindings to FFmpeg's C APIs, which work with raw memory pointers. The high-level API adds safety abstractions and automatic resource management, but incorrect usage can still cause crashes. Common issues include mismatched video dimensions, incompatible pixel formats, or improper frame buffer handling. The library validates parameters where possible, but can't guarantee complete memory safety without limiting functionality. When using the low-level API, pay attention to parameter consistency, resource cleanup, and format compatibility. Following the documented patterns helps avoid memory-related issues.Electron ​NodeAV fully supports Electron applications. The prebuilt binaries are ABI-compatible with Electron, so no native rebuild is required during packaging. Both the native bindings and the bundled FFmpeg CLI binaries work seamlessly within Electron's main process.NodeAV also supports Electron's offscreen rendering with shared textures, enabling zero-copy GPU texture import for hardware-accelerated encoding. See the Electron Builder and Electron Forge examples for complete implementations.If you encounter module resolution errors like Cannot find module 'lib/binary-stream', add this override to your project's package.json:json{
 "overrides": {
 "@shinyoshiaki/binary-data": "npm:@seydx/binary-data@0.6.2"
 }
}Examples ​The repository ships 60+ runnable examples covering both API levels — high-level (api-*: transcoding, hardware acceleration, RTSP, fMP4/DASH, RTP, Whisper, device capture, …) and low-level ports of the official FFmpeg C examples.→ Browse all examplesPrebuilt Binaries ​Prebuilt binaries are available for multiple platforms:macOS: x64, ARM64Linux: x64, ARM64Windows: x64, ARM64 (automatic MSVC/MinGW selection)Cross-Platform Packaging (CI/CD) ​By default the install step fetches the native binding and FFmpeg binary for the host platform. When packaging for a different target (e.g. building a Windows Electron app from a Linux CI runner), pass npm's standard --os / --cpu flags:bash# Install Windows x64 binaries while running on Linux
npm install --os=win32 --cpu=x64npm filters the platform-specific optionalDependencies by these flags, and the postinstall hook honors them for the bundled FFmpeg binary as well. Cross-compiled Windows installs default to the MSVC build; pass --libc=mingw to select the MinGW (jellyfin) build instead.Troubleshooting ​Hardware Acceleration on Linux (Intel/VAAPI) ​For hardware-accelerated video processing with Intel GPUs on Linux, you need to install specific system packages. The FFmpeg binaries included with this library are built with libva 2.20, which requires Ubuntu 24.04+ or Debian 13+ as minimum OS versions.Installation Steps ​Add Kisak-Mesa PPA (recommended for newer Mesa versions with better hardware support):bashsudo add-apt-repository ppa:kisak/kisak-mesa
sudo apt updateInstall required packages:bashsudo apt install libmfx-gen1.2 mesa-va-drivers mesa-vulkan-drivers libva2 libva-drm2 vainfo libvulkan1 vulkan-toolsAfter installation, verify hardware acceleration is working:bash# Check VAAPI support
vainfo

# Check Vulkan support
vulkaninfo

# Should show available profiles and entrypoints for your Intel GPUNote: If you're running an older Ubuntu version (< 24.04) or Debian version (< 13), you'll need to upgrade your OS to use hardware acceleration with this library.License ​This project is licensed under the MIT License. See the LICENSE file for details.Important: FFmpeg itself is licensed under LGPL/GPL. Please ensure compliance with FFmpeg's license terms when using this library. The FFmpeg libraries themselves retain their original licenses, and this wrapper library does not change those terms. See FFmpeg License for details.Contributing ​Contributions are welcome! Please read CONTRIBUTING.md for development setup, code standards, and contribution guidelines before submitting pull requests.Support ​For issues and questions, please use the GitHub issue tracker.See Also ​FFmpeg DocumentationFFmpeg DoxygenJellyfin FFmpegFFmpeg MSVC ​

